const MODULE_ID = "substances-and-paraphernalia";
if (!game.user.isGM) {
  ui.notifications.warn("Only the GM can toggle paraphernalia enforcement.");
  return;
}
const current = game.settings.get(MODULE_ID, "enforceParaphernalia");
const next = !current;
await game.settings.set(MODULE_ID, "enforceParaphernalia", next);
ui.notifications.info(`Paraphernalia enforcement is now ${next ? "ON" : "OFF"}.`);
